import { useState, useRef } from "react";

const PRESET_LOGOS = [
  { id: "green", label: "Зелёный", url: "data:image/png;base64," },
  { id: "white", label: "Белый", url: "data:image/png;base64," },
];


const ICON_MAP = {
  "Высота": "↑",
  "Ширина": "↔",
  "Место посадки": "☀",
  "Зона зимостойкости": "❄",
  "Цветение": "✿",
  "Устойчивость к болезням": "🛡",
  "Устойчивость к дождю": "🌧",
  "Размер цветка": "✾",
  "Размер соцветия": "❋",
  "Аромат": "◈",
  "Цвет цветков": "◉",
};

const STAR_PARAMS = ["Устойчивость к болезням", "Устойчивость к дождю", "Аромат"];

function parseStars(val) {
  if (!val) return null;
  const m = String(val).match(/(\d)/);
  return m ? parseInt(m[1]) : null;
}

function Stars({ count, max = 3 }) {
  return (
    <span style={{ letterSpacing: 1 }}>
      {Array.from({ length: max }, (_, i) => (
        <span key={i} style={{ opacity: i < count ? 1 : 0.25 }}>★</span>
      ))}
    </span>
  );
}

export default function App() {
  // Settings
  const [settings, setSettings] = useState({
    logoUrl: PRESET_LOGOS[0].url,
    logoId: "green",
    logoPos: "top-left",
    bgColor: "#74ab2c",
    textColor: "#ffffff",
  });
  const logoInputRef = useRef();

  // Card creation
  const [plantName, setPlantName] = useState("");
  const [photo, setPhoto] = useState(null);
  const photoInputRef = useRef();
  const [loading, setLoading] = useState(false);
  const [params, setParams] = useState(null);
  const [selectedParams, setSelectedParams] = useState([]);
  const [editingIdx, setEditingIdx] = useState(null);
  const canvasRef = useRef();
  const [previewUrl, setPreviewUrl] = useState(null);
  const [step, setStep] = useState(1); // 1=photo+name, 2=params, 3=preview

  const [descGroup, setDescGroup] = useState("");
  const [descBreeder, setDescBreeder] = useState("");
  const [descExperience, setDescExperience] = useState("");
  const [descExtra, setDescExtra] = useState("");
  const [descLoading, setDescLoading] = useState(false);
  const [descSections, setDescSections] = useState(null);
  const [copiedKey, setCopiedKey] = useState(null);

  const handleCopy = (key, text) => {
    navigator.clipboard.writeText(text);
    setCopiedKey(key);
    setTimeout(() => setCopiedKey(null), 2000);
  };

  const generateDescription = async () => {
    setDescLoading(true);
    setDescSections(null);
    try {
      const res = await fetch("/api/generate-description", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          plantName,
          params,
          group: descGroup,
          breeder: descBreeder,
          experience: descExperience,
          extra: descExtra,
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Server error");
      setDescSections(data.sections);
    } catch (e) {
      alert("Ошибка при генерации описания. Попробуйте ещё раз.");
    }
    setDescLoading(false);
  };

  const handleLogoUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => setSettings(s => ({ ...s, logoUrl: ev.target.result, logoId: "custom" }));
    reader.readAsDataURL(file);
  };

  const handlePhotoUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => setPhoto(ev.target.result);
    reader.readAsDataURL(file);
  };

  const fetchParams = async () => {
    if (!plantName.trim()) return;
    setLoading(true);
    try {
      const res = await fetch("/api/plant-params", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ plantName }),
      });
      const parsed = await res.json();
      if (!res.ok) throw new Error(parsed.error || "Server error");
      setParams(parsed);
      setSelectedParams([]);
      setEditingIdx(null);
      setPreviewUrl(null);
      setStep(2);
    } catch (e) {
      alert("Ошибка при получении данных. Попробуйте ещё раз.");
    }
    setLoading(false);
  };

  const toggleParam = (i) => {
    setSelectedParams(prev =>
      prev.includes(i) ? prev.filter(x => x !== i) : [...prev, i]
    );
  };

  const addCustomParam = () => {
    const newIdx = params.length;
    setParams(p => [...p, { label: "Параметр", value: "Значение" }]);
    setSelectedParams(p => [...p, newIdx]);
    setEditingIdx(newIdx);
  };

  const updateParam = (i, field, val) => {
    setParams(p => p.map((item, idx) => idx === i ? { ...item, [field]: val } : item));
  };

  // drawCard receives current values explicitly to avoid stale closure issues
  const drawCard = async (currentParams, currentSelectedParams) => {
    // Inject Google Fonts link if not already present
    if (!document.querySelector("#open-sans-link")) {
      const link = document.createElement("link");
      link.id = "open-sans-link";
      link.rel = "stylesheet";
      link.href = "https://fonts.googleapis.com/css2?family=Open+Sans:wght@400;700&display=block";
      document.head.appendChild(link);
      // Give the stylesheet a moment to parse and trigger font downloads
      await new Promise(r => setTimeout(r, 100));
    }

    // Wait for Open Sans specifically, with a 4s timeout fallback
    try {
      await Promise.race([
        Promise.all([
          document.fonts.load("700 20px 'Open Sans'"),
          document.fonts.load("400 20px 'Open Sans'"),
        ]),
        new Promise(r => setTimeout(r, 4000)),
      ]);
    } catch (e) { /* fall back to system font */ }

    const canvas = canvasRef.current;
    if (!canvas) return;
    const SIZE = 800;
    canvas.width = SIZE;
    canvas.height = SIZE;
    const ctx = canvas.getContext("2d");

    // Draw photo background
    if (photo) {
      await new Promise((resolve) => {
        const img = new Image();
        img.onload = () => {
          const scale = Math.max(SIZE / img.width, SIZE / img.height);
          const w = img.width * scale;
          const h = img.height * scale;
          ctx.drawImage(img, (SIZE - w) / 2, (SIZE - h) / 2, w, h);
          resolve();
        };
        img.src = photo;
      });
    } else {
      ctx.fillStyle = "#4a7c3f";
      ctx.fillRect(0, 0, SIZE, SIZE);
    }

    // Gradient overlay at bottom
    const grad = ctx.createLinearGradient(0, SIZE * 0.35, 0, SIZE);
    grad.addColorStop(0, "rgba(0,0,0,0)");
    grad.addColorStop(0.4, "rgba(0,0,0,0.25)");
    grad.addColorStop(1, "rgba(0,0,0,0.6)");
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, SIZE, SIZE);

    const active = currentSelectedParams
      .filter(i => currentParams[i])
      .sort((a, b) => a - b)
      .map(i => currentParams[i]);

    const bgColor = settings.bgColor;
    const textColor = settings.textColor;

    const FONT_SIZE = 26;
    const LINE_H = FONT_SIZE * 1.35;
    const PILL_PAD_X = 18;
    const PILL_PAD_Y = 10;
    const GAP_X = 10;
    const GAP_Y = 10;
    const PILL_RADIUS = 22;
    const MARGIN = 20;
    const MAX_W = SIZE - MARGIN * 2;

    function wrapText(ctx, text, maxWidth) {
      const words = text.split(" ");
      const lines = [];
      let line = "";
      for (const word of words) {
        const test = line ? line + " " + word : word;
        if (ctx.measureText(test).width > maxWidth && line) {
          lines.push(line);
          line = word;
        } else {
          line = test;
        }
      }
      if (line) lines.push(line);
      return lines;
    }

    // Measure each pill's width and height
    const pills = active.map(p => {
      const isStarParam = STAR_PARAMS.includes(p.label);
      const starCount = isStarParam ? parseStars(p.value) : null;
      const icon = ICON_MAP[p.label] || "•";
      const labelText = `${icon} ${p.label}:`;
      const valText = (!isStarParam) ? p.value : null;

      // Try single-line first (label + value side by side)
      ctx.font = `bold ${FONT_SIZE}px 'Open Sans'`;
      const labelW = ctx.measureText(labelText).width;
      ctx.font = `${FONT_SIZE}px 'Open Sans'`;
      const valW = valText ? ctx.measureText("  " + valText).width
                           : isStarParam ? (FONT_SIZE + 4) * 3 : 0;

      const singleLineW = PILL_PAD_X * 2 + labelW + valW + 8;

      let pillW, pillH, multiLine = false;

      if (singleLineW <= MAX_W) {
        // Fits on one line
        pillW = singleLineW;
        pillH = PILL_PAD_Y * 2 + LINE_H;
      } else {
        // Wrap: label on its own lines, value on its own lines
        multiLine = true;
        pillW = Math.min(singleLineW, MAX_W);
        const innerW = pillW - PILL_PAD_X * 2;
        ctx.font = `bold ${FONT_SIZE}px 'Open Sans'`;
        const lLines = wrapText(ctx, labelText, innerW);
        ctx.font = `${FONT_SIZE}px 'Open Sans'`;
        const vLines = valText ? wrapText(ctx, valText, innerW) : [];
        const totalLines = lLines.length + (valText ? vLines.length : (isStarParam ? 1 : 0));
        pillH = PILL_PAD_Y * 2 + totalLines * LINE_H;
      }

      return { p, isStarParam, starCount, icon, labelText, valText, labelW, valW, pillW, pillH, multiLine };
    });

    // Staggered layout: pack pills row by row from bottom
    // First, lay them out top-down, then offset everything to bottom
    const rows = [];
    let rowX = MARGIN;
    let currentRow = [];
    let currentRowH = 0;

    for (const pill of pills) {
      if (rowX + pill.pillW > SIZE - MARGIN && currentRow.length > 0) {
        rows.push({ items: currentRow, rowH: currentRowH });
        currentRow = [];
        rowX = MARGIN;
        currentRowH = 0;
      }
      currentRow.push({ ...pill, x: rowX });
      rowX += pill.pillW + GAP_X;
      currentRowH = Math.max(currentRowH, pill.pillH);
    }
    if (currentRow.length > 0) rows.push({ items: currentRow, rowH: currentRowH });

    // Total height, anchor to bottom
    const totalH = rows.reduce((s, r) => s + r.rowH + GAP_Y, 0);
    let curY = SIZE - MARGIN - totalH;

    for (const row of rows) {
      for (const pill of row.items) {
        const { x, pillW, pillH, labelText, valText, isStarParam, starCount, labelW, valW, multiLine } = pill;
        const innerW = pillW - PILL_PAD_X * 2;

        // Background
        ctx.fillStyle = bgColor;
        ctx.globalAlpha = 0.92;
        roundRect(ctx, x, curY, pillW, pillH, PILL_RADIUS);
        ctx.fill();
        ctx.globalAlpha = 1;

        ctx.textAlign = "left";
        ctx.textBaseline = "middle";

        if (!multiLine) {
          // Single line: vertically centered in pill
          const textY = curY + pillH / 2;
          ctx.font = `bold ${FONT_SIZE}px 'Open Sans'`;
          ctx.fillStyle = textColor;
          ctx.fillText(labelText, x + PILL_PAD_X, textY);

          if (isStarParam && starCount !== null) {
            ctx.font = `${FONT_SIZE + 2}px 'Open Sans'`;
            for (let s = 0; s < 3; s++) {
              ctx.fillStyle = s < starCount ? "#FFD700" : "rgba(255,255,255,0.3)";
              ctx.fillText("★", x + PILL_PAD_X + labelW + 8 + s * (FONT_SIZE + 4), textY);
            }
          } else if (valText) {
            ctx.font = `${FONT_SIZE}px 'Open Sans'`;
            ctx.fillStyle = textColor;
            ctx.fillText("  " + valText, x + PILL_PAD_X + labelW, textY);
          }
        } else {
          // Multi-line: start first line centered in its row slot
          let ty = curY + PILL_PAD_Y + LINE_H / 2;
          ctx.font = `bold ${FONT_SIZE}px 'Open Sans'`;
          ctx.fillStyle = textColor;
          const lLines = wrapText(ctx, labelText, innerW);
          for (const line of lLines) { ctx.fillText(line, x + PILL_PAD_X, ty); ty += LINE_H; }

          if (isStarParam && starCount !== null) {
            ctx.font = `${FONT_SIZE + 2}px 'Open Sans'`;
            for (let s = 0; s < 3; s++) {
              ctx.fillStyle = s < starCount ? "#FFD700" : "rgba(255,255,255,0.3)";
              ctx.fillText("★", x + PILL_PAD_X + s * (FONT_SIZE + 4), ty);
            }
          } else if (valText) {
            ctx.font = `${FONT_SIZE}px 'Open Sans'`;
            ctx.fillStyle = textColor;
            const vLines = wrapText(ctx, valText, innerW);
            for (const line of vLines) { ctx.fillText(line, x + PILL_PAD_X, ty); ty += LINE_H; }
          }
        }
      }
      curY += row.rowH + GAP_Y;
    }

    // Logo — preserve aspect ratio, fit within MAX_LOGO box
    if (settings.logoUrl) {
      await new Promise((resolve) => {
        const img = new Image();
        img.onload = () => {
          const MAX_LOGO = 220;
          const margin = 20;
          const ratio = img.width / img.height;
          let lw, lh;
          if (ratio >= 1) { lw = MAX_LOGO; lh = MAX_LOGO / ratio; }
          else { lh = MAX_LOGO; lw = MAX_LOGO * ratio; }
          let lx, ly;
          if (settings.logoPos === "top-left")    { lx = margin; ly = margin; }
          else if (settings.logoPos === "top-right")   { lx = SIZE - lw - margin; ly = margin; }
          else if (settings.logoPos === "bottom-left") { lx = margin; ly = SIZE - lh - margin; }
          else                                          { lx = SIZE - lw - margin; ly = SIZE - lh - margin; }
          ctx.drawImage(img, lx, ly, lw, lh);
          resolve();
        };
        img.onerror = resolve;
        img.src = settings.logoUrl;
      });
    }

    setPreviewUrl(canvas.toDataURL("image/jpeg", 0.95));
    setStep(3);
  };

  function roundRect(ctx, x, y, w, h, r) {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  }

  const downloadCard = () => {
    const a = document.createElement("a");
    a.href = previewUrl;
    a.download = `${plantName.replace(/\s+/g, "_")}_card.jpg`;
    a.target = "_blank";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  return (
    <div style={{
      minHeight: "100vh",
      background: "#f2f5ef",
      fontFamily: "'Georgia', serif",
      color: "#1a2d0f",
      padding: "0 0 60px 0",
    }}>
      {/* Header */}
      <div style={{
        background: "#ffffff",
        borderBottom: "1px solid #dde8d5",
        padding: "18px 32px",
      }}>
        <div style={{ fontSize: 22, fontWeight: "bold", letterSpacing: 2, color: "#2d6a10" }}>
          🌿 RozaRugoza Card Studio
        </div>
        <div style={{ fontSize: 12, color: "#6a9a50", letterSpacing: 1 }}>Генератор карточек растений. Для семьи с любовью.</div>
      </div>

      {/* Settings Panel — always open */}
      <div style={{
        background: "#eaf0e4",
        borderBottom: "1px solid #dde8d5",
        padding: "20px 32px",
      }}>
        <div style={{ maxWidth: 900, margin: "0 auto", display: "flex", gap: 32, flexWrap: "wrap", alignItems: "flex-start" }}>

          {/* Logo presets */}
          <div>
            <Label>Логотип</Label>
            <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
              {PRESET_LOGOS.map(logo => (
                <div
                  key={logo.id}
                  onClick={() => setSettings(s => ({ ...s, logoUrl: logo.url, logoId: logo.id }))}
                  style={{
                    width: 80, height: 80, borderRadius: 10, overflow: "hidden", cursor: "pointer",
                    border: settings.logoId === logo.id ? "2px solid #a8d878" : "2px solid transparent",
                    background: logo.id === "white" ? "#222" : "#111",
                    display: "flex", alignItems: "center", justifyContent: "center",
                    padding: 6, boxSizing: "border-box",
                    transition: "border 0.15s",
                  }}
                >
                  <img src={logo.url} alt={logo.label} style={{ width: "100%", height: "100%", objectFit: "contain" }} />
                </div>
              ))}
              {/* Custom upload */}
              <div>
                <input ref={logoInputRef} type="file" accept="image/*" onChange={handleLogoUpload} style={{ display: "none" }} />
                <div
                  onClick={() => logoInputRef.current.click()}
                  style={{
                    width: 80, height: 80, borderRadius: 10, cursor: "pointer",
                    border: (!settings.logoId || settings.logoId === "custom") && settings.logoUrl && !PRESET_LOGOS.find(l => l.id === settings.logoId)
                      ? "2px solid #a8d878" : "2px dashed rgba(168,216,120,0.35)",
                    background: "rgba(255,255,255,0.03)",
                    display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
                    fontSize: 11, color: "#6a9a50", gap: 4,
                  }}
                >
                  <span style={{ fontSize: 22 }}>📂</span>
                  <span>Свой</span>
                </div>
              </div>
            </div>
          </div>

          {/* Logo position */}
          <div>
            <Label>Позиция логотипа</Label>
            <select
              value={settings.logoPos}
              onChange={e => setSettings(s => ({ ...s, logoPos: e.target.value }))}
              style={selectStyle}
            >
              <option value="top-left">Верхний левый</option>
              <option value="top-right">Верхний правый</option>
              <option value="bottom-left">Нижний левый</option>
              <option value="bottom-right">Нижний правый</option>
            </select>
          </div>

          {/* Colors */}
          <div>
            <Label>Цвет заливки параметров</Label>
            <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
              <input type="color" value={settings.bgColor}
                onChange={e => setSettings(s => ({ ...s, bgColor: e.target.value }))}
                style={{ width: 44, height: 36, border: "none", borderRadius: 6, cursor: "pointer" }} />
              <span style={{ fontSize: 12, color: "#6a9a50" }}>{settings.bgColor}</span>
            </div>
          </div>
          <div>
            <Label>Цвет текста</Label>
            <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
              <input type="color" value={settings.textColor}
                onChange={e => setSettings(s => ({ ...s, textColor: e.target.value }))}
                style={{ width: 44, height: 36, border: "none", borderRadius: 6, cursor: "pointer" }} />
              <span style={{ fontSize: 12, color: "#6a9a50" }}>{settings.textColor}</span>
            </div>
          </div>

        </div>
      </div>

      <div style={{ maxWidth: 900, margin: "0 auto", padding: "24px 32px" }}>
        {/* Step 1 */}
        <StepCard step={1} currentStep={step} title="1. Фото и название растения">
          <div style={{ display: "flex", gap: 24, flexWrap: "wrap" }}>
            {/* Photo upload */}
            <div style={{ position: "relative", width: 180, height: 180, flexShrink: 0 }}>
              <div
                onClick={() => photoInputRef.current.click()}
                style={{
                  width: 180, height: 180, borderRadius: 12,
                  border: `2px dashed ${photo ? "rgba(168,216,120,0.6)" : "rgba(168,216,120,0.35)"}`,
                  display: "flex", flexDirection: "column",
                  alignItems: "center", justifyContent: "center",
                  cursor: "pointer",
                  overflow: "hidden", position: "relative",
                  background: photo ? "none" : "rgba(255,255,255,0.03)",
                }}
              >
                {photo ? (
                  <img src={photo} alt="" style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
                ) : (
                  <>
                    <div style={{ fontSize: 36 }}>📷</div>
                    <div style={{ fontSize: 12, color: "#6a9a50", marginTop: 8, textAlign: "center" }}>
                      Загрузить фото<br />(или сделать снимок)
                    </div>
                  </>
                )}
              </div>
              {photo && (
                <div
                  onClick={() => photoInputRef.current.click()}
                  style={{
                    position: "absolute", bottom: 8, right: 8,
                    background: "rgba(0,0,0,0.6)", borderRadius: 6,
                    padding: "4px 8px", fontSize: 14, color: "#ffffff",
                    cursor: "pointer", backdropFilter: "blur(4px)",
                  }}
                >✏ Заменить</div>
              )}
              <input ref={photoInputRef} type="file" accept="image/*"
                onChange={handlePhotoUpload} style={{ display: "none" }} />
            </div>
            {/* Name + button */}
            <div style={{ flex: 1, minWidth: 200, display: "flex", flexDirection: "column", gap: 16 }}>
              <div>
                <Label>Полное название растения</Label>
                <input
                  value={plantName}
                  onChange={e => setPlantName(e.target.value)}
                  onKeyDown={e => e.key === "Enter" && fetchParams()}
                  placeholder="Гортензия метельчатая Polar Bear"
                  style={{
                    width: "100%", background: "#fff",
                    border: "1px solid #c5d9b0",
                    borderRadius: 8, color: "#111", fontSize: 15,
                    padding: "10px 14px", outline: "none",
                    fontFamily: "Georgia, serif",
                  }}
                />
              </div>
              <button
                onClick={fetchParams}
                disabled={loading || !plantName.trim()}
                style={{
                  ...btnStyle("#2d7a1b"),
                  padding: "12px 24px", fontSize: 15,
                  opacity: loading || !plantName.trim() ? 0.5 : 1,
                }}
              >
                {loading ? "🔍 Поиск характеристик..." : "🔍 Сгенерировать параметры"}
              </button>
            </div>
          </div>
        </StepCard>

        {/* Step 2 */}
        {step >= 2 && params && (
          <StepCard step={2} currentStep={step} title="2. Выберите параметры для карточки">
            <div style={{ marginBottom: 16, color: "#5a8a40", fontSize: 13 }}>
              Нажмите на карточку чтобы добавить/убрать параметр. Нажмите на ✏ для редактирования.
            </div>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 20, alignItems: "flex-start" }}>
              {params.map((p, i) => {
                const active = selectedParams.includes(i);
                const isEditing = editingIdx === i;
                return (
                  <div key={i} style={{
                    display: "inline-flex", alignItems: "center", gap: 8,
                    background: active ? settings.bgColor : "#f5f8f2",
                    border: `1px solid ${active ? "transparent" : "#dde8d5"}`,
                    borderRadius: 12, padding: "8px 12px",
                    cursor: isEditing ? "default" : "pointer",
                    transition: "all 0.15s",
                    maxWidth: isEditing ? 320 : "none",
                    flexShrink: 0,
                  }}>
                    {isEditing ? (
                      <div style={{ display: "flex", flexDirection: "column", gap: 6, width: 280 }}>
                        <input
                          value={p.label}
                          onChange={e => updateParam(i, "label", e.target.value)}
                          placeholder="Название параметра"
                          style={{
                            width: "100%", background: "#f5f8f2", border: "1px solid #c5d9b0",
                            borderRadius: 6, color: "#1a2d0f", fontSize: 13, padding: "4px 8px", outline: "none",
                          }}
                          onClick={e => e.stopPropagation()}
                        />
                        <input
                          value={p.value}
                          onChange={e => updateParam(i, "value", e.target.value)}
                          placeholder="Значение"
                          style={{
                            width: "100%", background: "#f5f8f2", border: "1px solid #c5d9b0",
                            borderRadius: 6, color: "#1a2d0f", fontSize: 13, padding: "4px 8px", outline: "none",
                          }}
                          onClick={e => e.stopPropagation()}
                        />
                        <span
                          onClick={e => { e.stopPropagation(); setEditingIdx(null); }}
                          style={{ color: "#2d6a10", cursor: "pointer", fontSize: 12, padding: "2px 8px", background: "#dff0cc", borderRadius: 4, alignSelf: "flex-start" }}
                        >✓ Готово</span>
                      </div>
                    ) : (
                      <>
                        <div
                          onClick={() => toggleParam(i)}
                          style={{ color: active ? settings.textColor : "#6a8a5a", fontSize: 13, lineHeight: 1.4 }}
                        >
                          <span style={{ fontWeight: "bold" }}>{ICON_MAP[p.label] || "•"} {p.label}:</span>{" "}
                          {STAR_PARAMS.includes(p.label)
                            ? "★".repeat(parseStars(p.value) || 1) + "☆".repeat(3 - (parseStars(p.value) || 1))
                            : p.value}
                        </div>
                        <span
                          onClick={e => { e.stopPropagation(); setEditingIdx(i); }}
                          style={{ color: "rgba(0,0,0,0.3)", cursor: "pointer", fontSize: 13, flexShrink: 0 }}
                        >✏</span>
                      </>
                    )}
                  </div>
                );
              })}
              <div
                onClick={addCustomParam}
                style={{
                  display: "inline-flex", alignItems: "center", gap: 6,
                  background: "#f5f8f2",
                  border: "1px dashed #a8c888",
                  borderRadius: 12, padding: "8px 12px",
                  cursor: "pointer", color: "#3a7a15", fontSize: 13, flexShrink: 0,
                }}
              >+ Добавить свой</div>
            </div>

            <button
              onClick={() => drawCard(params, selectedParams)}
              style={{ ...btnStyle("#2d7a1b"), padding: "12px 32px", fontSize: 15 }}
            >
              🖼 Сформировать карточку
            </button>

            <div style={{ marginTop: 36, borderTop: "1px solid #dde8d5", paddingTop: 28 }}>
              <div style={{ color: "#2d6a10", fontSize: 15, fontWeight: "bold", marginBottom: 4 }}>
                📝 Описание для сайта
              </div>
              <div style={{ color: "#5a8a40", fontSize: 12, marginBottom: 20 }}>
                Параметры подставятся автоматически. Заполните дополнительные поля для более точного текста.
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, marginBottom: 12 }}>
                <div>
                  <div style={{ color: "#5a7a45", fontSize: 12, marginBottom: 4 }}>Группа / тип</div>
                  <input
                    value={descGroup}
                    onChange={e => setDescGroup(e.target.value)}
                    placeholder="напр. Плетистая роза, Флорибунда"
                    style={{ width: "100%", background: "#fff", border: "1px solid #c5d9b0", borderRadius: 8, color: "#1a2d0f", fontSize: 13, padding: "8px 12px", outline: "none", boxSizing: "border-box" }}
                  />
                </div>
                <div>
                  <div style={{ color: "#5a7a45", fontSize: 12, marginBottom: 4 }}>Селекционер и год</div>
                  <input
                    value={descBreeder}
                    onChange={e => setDescBreeder(e.target.value)}
                    placeholder="напр. Meilland, 1992"
                    style={{ width: "100%", background: "#fff", border: "1px solid #c5d9b0", borderRadius: 8, color: "#1a2d0f", fontSize: 13, padding: "8px 12px", outline: "none", boxSizing: "border-box" }}
                  />
                </div>
              </div>
              <div style={{ marginBottom: 12 }}>
                <div style={{ color: "#5a7a45", fontSize: 12, marginBottom: 4 }}>Наш опыт выращивания <span style={{ color: "#5a8a40" }}>(рекомендуется)</span></div>
                <textarea
                  value={descExperience}
                  onChange={e => setDescExperience(e.target.value)}
                  placeholder="напр. Зимует без укрытия уже 5 лет, цветёт с июня по октябрь без перерыва, болезней не замечали..."
                  rows={3}
                  style={{ width: "100%", background: "#fff", border: "1px solid #c5d9b0", borderRadius: 8, color: "#1a2d0f", fontSize: 13, padding: "8px 12px", outline: "none", resize: "vertical", boxSizing: "border-box" }}
                />
              </div>
              <div style={{ marginBottom: 20 }}>
                <div style={{ color: "#5a7a45", fontSize: 12, marginBottom: 4 }}>Дополнительные особенности</div>
                <textarea
                  value={descExtra}
                  onChange={e => setDescExtra(e.target.value)}
                  placeholder="напр. Отлично подходит для вертикального озеленения, подвязки не требует..."
                  rows={2}
                  style={{ width: "100%", background: "#fff", border: "1px solid #c5d9b0", borderRadius: 8, color: "#1a2d0f", fontSize: 13, padding: "8px 12px", outline: "none", resize: "vertical", boxSizing: "border-box" }}
                />
              </div>
              <button
                onClick={generateDescription}
                disabled={descLoading}
                style={{ ...btnStyle("#1a5a7a"), padding: "12px 32px", fontSize: 15, opacity: descLoading ? 0.6 : 1 }}
              >
                {descLoading ? "⏳ Генерирую описание..." : "✍️ Сгенерировать описание"}
              </button>
              {descSections && (
                <div style={{ marginTop: 24, display: "flex", flexDirection: "column", gap: 12 }}>
                  {[
                    { key: "meta",     label: "Мета-теги" },
                    { key: "intro",    label: "Краткое описание" },
                    { key: "main",     label: "Основное описание" },
                    { key: "table",    label: "Таблица характеристик" },
                    { key: "faq",      label: "Вопрос — Ответ" },
                    { key: "keywords", label: "Ключевые слова" },
                  ].filter(s => descSections[s.key]).map(s => (
                    <div key={s.key} style={{ background: "#fff", border: "1px solid #dde8d5", borderRadius: 10, overflow: "hidden" }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "10px 16px", borderBottom: "1px solid #edf3e8", background: "#f7faf4" }}>
                        <div style={{ color: "#2d6010", fontSize: 13, fontWeight: "bold" }}>{s.label}</div>
                        <button
                          onClick={() => handleCopy(s.key, descSections[s.key])}
                          style={{ ...btnStyle(copiedKey === s.key ? "#3a8a1a" : "#5a7a4a"), padding: "4px 14px", fontSize: 12, transition: "background 0.2s" }}
                        >
                          {copiedKey === s.key ? "✓ Скопировано" : "📋 Скопировать"}
                        </button>
                      </div>
                      <pre style={{
                        margin: 0, padding: "12px 16px", color: "#2a3d1a",
                        fontSize: 13, lineHeight: 1.7, whiteSpace: "pre-wrap",
                        wordBreak: "break-word", fontFamily: "inherit",
                      }}>
                        {descSections[s.key]}
                      </pre>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </StepCard>
        )}

        {/* Step 3 - Preview */}
        {step >= 3 && previewUrl && (
          <StepCard step={3} currentStep={step} title="3. Готовая карточка">
            <div style={{ display: "flex", gap: 24, flexWrap: "wrap", alignItems: "flex-start" }}>
              <img
                src={previewUrl}
                alt="card"
                style={{ width: 360, height: 360, borderRadius: 12, objectFit: "cover", boxShadow: "0 8px 40px rgba(0,0,0,0.5)" }}
              />
              <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
                <a
                  href={previewUrl}
                  download={`${plantName.replace(/\s+/g, "_")}_card.jpg`}
                  style={{ ...btnStyle("#1a7a30"), padding: "14px 32px", fontSize: 16, textDecoration: "none", display: "inline-block", textAlign: "center" }}
                >
                  ⬇ Скачать JPG
                </a>
                <button onClick={() => { setStep(2); setPreviewUrl(null); }} style={{ ...btnStyle("#333"), padding: "10px 24px", fontSize: 14 }}>
                  ← Изменить параметры
                </button>
                <button onClick={() => { setStep(1); setParams(null); setSelectedParams([]); setEditingIdx(null); setPhoto(null); setPlantName(""); setPreviewUrl(null); }}
                  style={{ ...btnStyle("#333"), padding: "10px 24px", fontSize: 14 }}>
                  🌱 Новая карточка
                </button>
              </div>
            </div>
          </StepCard>
        )}
      </div>

      <canvas ref={canvasRef} style={{ display: "none" }} />
    </div>
  );
}

function StepCard({ children, title }) {
  return (
    <div style={{
      background: "#ffffff",
      border: "1px solid #dde8d5",
      borderRadius: 14,
      padding: 24,
      marginBottom: 20,
      boxShadow: "0 1px 4px rgba(0,0,0,0.06)",
    }}>
      <div style={{ fontSize: 17, fontWeight: "bold", color: "#2d6a10", marginBottom: 18, letterSpacing: 0.5 }}>{title}</div>
      {children}
    </div>
  );
}

function Label({ children }) {
  return <div style={{ fontSize: 12, color: "#5a8a40", marginBottom: 8, letterSpacing: 0.5, textTransform: "uppercase" }}>{children}</div>;
}

const btnStyle = (bg) => ({
  background: bg,
  border: "none",
  color: "#ffffff",
  borderRadius: 8,
  cursor: "pointer",
  fontFamily: "Georgia, serif",
  letterSpacing: 0.5,
  transition: "opacity 0.15s",
});

const selectStyle = {
  background: "#ffffff",
  border: "1px solid #c5d9b0",
  borderRadius: 8,
  color: "#1a2d0f",
  fontSize: 14,
  padding: "8px 12px",
  outline: "none",
  cursor: "pointer",
};
